#!/usr/bin/env node
// verify-ws.mjs — end-to-end TRUE-per-tick proof through the live recon-server WS.
// Boots the recon node, opens the perception WS, streams N synthetic RGB24 frames,
// and asserts: one TICK out per FRAME in (per-tick, not window-batched), the wire is
// the packed bitwise tick (decodes via perception-wire), and the tick carries the
// worldsim-state fields the body-frame fusion reads (entities/metacog/...).
import { spawn } from 'node:child_process';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { WebSocket } from 'ws';
import { decodeMessage } from '../../../../apps/monster-studio/src/lib/perception-wire.ts';
import { encodeFrame } from '../../../../apps/monster-studio/src/lib/perception-wire.ts';

const HERE = dirname(fileURLToPath(import.meta.url));
const RECON = resolve(HERE, '../../../../apps/monster-studio/scripts/recon-server.mjs');
const PORT = 8799;
const W = 192, H = 108, FPS = 24, N = 35;
const frameBytes = W * H * 3;

function frame(f) {
  const buf = new Uint8Array(frameBytes).fill(28);
  const bw = 28, bh = 28;
  const bx = Math.round((W - bw) * (f / (N - 1)));
  const by = Math.round(H / 2 - bh / 2);
  for (let y = by; y < by + bh; y++)
    for (let x = bx; x < bx + bw; x++) {
      const p = (y * W + x) * 3;
      buf[p] = 230; buf[p + 1] = 90; buf[p + 2] = 40;
    }
  return buf;
}

const node = spawn('node', [RECON], {
  env: { ...process.env, RECON_PORT: String(PORT) },
  stdio: ['ignore', 'pipe', 'pipe'],
});
let serverLog = '';
node.stdout.on('data', (c) => { serverLog += c.toString(); });
node.stderr.on('data', (c) => { serverLog += c.toString(); });

function waitFor(re, ms) {
  return new Promise((res, rej) => {
    const t = setInterval(() => { if (re.test(serverLog)) { clearInterval(t); res(); } }, 50);
    setTimeout(() => { clearInterval(t); rej(new Error(`timeout waiting for ${re}`)); }, ms);
  });
}

const fail = (m) => { console.error('[ws] FAIL:', m); console.error(serverLog.slice(-1200)); node.kill(); process.exit(1); };

try {
  await waitFor(/multi-view union sidecar/, 8000);
  const wasmMode = /perception WASM loaded/.test(serverLog);
  console.log(`[ws] node up on ${PORT}; perception mode = ${wasmMode ? 'WASM per-tick' : 'native fallback'}`);

  const ws = new WebSocket(`ws://127.0.0.1:${PORT}/api/v1/thoth/perceive-stream`);
  ws.binaryType = 'arraybuffer';
  let ticks = 0, ready = false, sampleTick = null;

  await new Promise((res, rej) => {
    const giveUp = setTimeout(() => rej(new Error('ws did not complete')), 20000);
    ws.on('open', () => {
      ws.send(JSON.stringify({ type: 'hello', mode: 'bitwise', width: W, height: H, fps: FPS, staticCam: true }));
    });
    ws.on('message', (data, isBinary) => {
      if (!isBinary) {
        let obj; try { obj = JSON.parse(data.toString('utf8')); } catch { return; }
        if (obj.type === 'ready') {
          ready = true;
          console.log(`[ws] ready: thirdEyeMode=${obj.thirdEyeMode}`);
          // Stream frames one at a time — per-tick path emits a tick per frame.
          let i = 0;
          const iv = setInterval(() => {
            if (i >= N) { clearInterval(iv); setTimeout(() => { ws.close(); clearTimeout(giveUp); res(); }, 800); return; }
            const wire = encodeFrame({ kind: 'frame', seq: i, w: W, h: H, fps: FPS, staticCam: true, rgb24: frame(i) }, 'bitwise');
            ws.send(wire); i++;
          }, 15);
          return;
        }
        if (obj.kind === 'error') rej(new Error('node error: ' + obj.message));
        return;
      }
      // Binary TICK frame — decode via the SAME wire codec the studio client uses.
      try {
        const msg = decodeMessage(new Uint8Array(data));
        if (msg.kind === 'tick') { ticks++; sampleTick = msg.tick; }
      } catch (e) { rej(new Error('tick decode failed: ' + e.message)); }
    });
    ws.on('error', rej);
  });

  console.log(`[ws] frames sent=${N}, ticks received=${ticks}`);
  if (!ready) fail('handshake never readied');
  if (wasmMode) {
    // TRUE per-tick: one tick per frame (allow the last in-flight frame to be dropped
    // by the close race; require near-1:1, not the old ~1 tick per 30-frame window).
    if (ticks < N - 2) fail(`expected ~${N} ticks (one per frame), got ${ticks} — not per-tick`);
    console.log(`[ws] PER-TICK CONFIRMED: ${ticks} ticks for ${N} frames (vs native micro-batch ~${Math.ceil(N / 30)} window ticks)`);
  } else {
    console.log(`[ws] native fallback active — ${ticks} window tick(s) (per-tick proof needs the wasm; it did not load)`);
  }
  // The tick feeds body-frame fusion: it must carry the worldsim-state fields.
  const fields = sampleTick ? Object.keys(sampleTick) : [];
  const hasFusionFields = sampleTick && 'entities' in sampleTick && 'metacog' in sampleTick && 'accumulatedKnowledge' in sampleTick;
  console.log(`[ws] tick fields: ${fields.join(', ')}`);
  console.log(`[ws] BODY-FRAME FUSION FED (entities+metacog+accumulatedKnowledge present): ${!!hasFusionFields}`);
  if (!hasFusionFields) fail('tick missing the fields the body-frame fusion reads');

  node.kill();
  console.log('[ws] PASS');
  process.exit(0);
} catch (e) {
  fail(e.message);
}
